// Parse order from Kafka and map to NetSuite sales order payload.
const kafkaMessage = $input.item.json;
const order = typeof kafkaMessage.value === 'string' ? JSON.parse(kafkaMessage.value) : kafkaMessage.value;

if (!order || !order.customer_id || !Array.isArray(order.line_items)) {
  throw new Error('invalid order payload: missing customer_id or line_items');
}

const netsuiteOrder = {
  entity: { id: order.customer_id },
  tranDate: order.order_date || new Date().toISOString().split('T')[0],
  otherRefNum: order.external_order_id,
  memo: order.notes || 'Created via integration',
  custbody_source_system: order.source || 'gateway',
  item: {
    items: order.line_items.map(item => ({
      item: { id: item.netsuite_item_id },
      quantity: item.quantity,
      rate: item.unit_price,
      amount: item.quantity * item.unit_price,
      description: item.description
    }))
  },
  shipAddress: order.shipping_address ? {
    addressee: order.shipping_address.name,
    addr1: order.shipping_address.street1,
    addr2: order.shipping_address.street2,
    city: order.shipping_address.city,
    state: order.shipping_address.state,
    zip: order.shipping_address.zip,
    country: order.shipping_address.country
  } : null
};

return {
  json: {
    netsuite_payload: netsuiteOrder,
    original_order: order,
    retry_count: order._retry_count || 0,
    max_retries: 5
  }
};

const response = $input.item.json;
const original = response.original_order || {};
return {
  json: {
    success: true,
    netsuite_sales_order_id: response.id,
    netsuite_order_number: response.tranId,
    external_order_id: original.external_order_id,
    timestamp: new Date().toISOString()
  }
};

// Normalize NetSuite error and decide retry vs DLQ.
const error = $input.item.json;
const original = error.original_order || {};
const retryCount = (error.retry_count || 0);
const maxRetries = error.max_retries || 5;
const status = error.status || error.statusCode || 0;
const isTransient = status === 429 || (status >= 500 && status < 600);
const shouldRetry = isTransient && retryCount < maxRetries;

return {
  json: {
    workflow: 'netsuite-create-sales-order',
    error_message: error.message || error['o:errorDetails']?.[0]?.detail || 'Unknown error',
    error_code: error['o:errorDetails']?.[0]?.['o:errorCode'] || status,
    retry_count: retryCount,
    max_retries: maxRetries,
    should_retry: shouldRetry,
    retry_delay_ms: Math.min(60000, 1000 * Math.pow(2, retryCount)) + Math.floor(Math.random() * 500),
    original_order: { ...original, _retry_count: retryCount + 1 },
    timestamp: new Date().toISOString()
  }
};
